import { useCallback } from 'react';

import CrudResourceModule from 'features/shared/components/CrudResourceModule';
import useSelectOptions from 'features/shared/useSelectOptions';

export default function VisitsPage() {
  const ownerLabelBuilder = useCallback((owner) => `${owner.parcel_code} - ${owner.full_name} (${owner.rut})`, []);
  const objectiveLabelBuilder = useCallback((objective) => objective.title, []);

  const ownerOptions = useSelectOptions('/maps/parcel-options/', ownerLabelBuilder, { include_inactive: 'true' });
  const objectiveOptions = useSelectOptions('/maps/objectives/', objectiveLabelBuilder);

  const columns = [
    { key: 'owner_parcel_code', label: 'Parcela' },
    { key: 'owner_display', label: 'Propietario' },
    { key: 'visitor_name', label: 'Visitante' },
    { key: 'visitor_rut', label: 'RUT' },
    { key: 'vehicle_plate', label: 'Patente' },
    { key: 'purpose', label: 'Motivo' },
    { key: 'visit_datetime', label: 'Fecha/Hora' }
  ];

  const fields = () => [
    { name: 'owner', label: 'Parcela / Propietario', type: 'select', options: ownerOptions, required: true },
    { name: 'objective', label: 'Objetivo', type: 'select', options: [{ value: '', label: 'Sin objetivo' }, ...objectiveOptions] },
    { name: 'visitor_name', label: 'Nombre visitante', required: true },
    { name: 'visitor_rut', label: 'RUT visitante' },
    { name: 'vehicle_plate', label: 'Patente' },
    { name: 'purpose', label: 'Motivo', required: true },
    { name: 'visit_datetime', label: 'Fecha/Hora', type: 'datetime-local', required: true },
    { name: 'notes', label: 'Notas', type: 'textarea', fullWidth: true }
  ];

  const mapPayload = (values) => ({
    ...values,
    objective: values.objective || null
  });

  return (
    <CrudResourceModule
      title="Visitas"
      path="/maps/visits/"
      columns={columns}
      fields={fields}
      defaultOrdering="-visit_datetime"
      mapPayload={mapPayload}
      searchPlaceholder="Buscar por visitante, RUT, patente o parcela (lote-numero)..."
    />
  );
}

